from text_utils import reverse, split_words, join_with
from math_utils import safe_divide, average, clamp
from list_utils import first_or_none, deduplicate


def test_reverse():
    assert reverse('hi') == 'ih'


def test_split_words():
    assert split_words('a b c') == ['a', 'b', 'c']


def test_join_with():
    assert join_with(['a', 'b']) == 'a, b'


def test_safe_divide_nonzero():
    assert safe_divide(10, 2) == 5


def test_safe_divide_zero():
    assert safe_divide(10, 0) is None


def test_average():
    assert average([1, 2, 3, 4]) == 2.5


def test_clamp():
    assert clamp(5, 0, 10) == 5
    assert clamp(-1, 0, 10) == 0
    assert clamp(99, 0, 10) == 10


def test_first_or_none_empty():
    assert first_or_none([]) is None


def test_first_or_none_present():
    assert first_or_none(['x', 'y']) == 'x'


def test_deduplicate():
    assert deduplicate([1, 2, 1, 3, 2]) == [1, 2, 3]

