from typing import Optional


def safe_divide(a: int, b: int) -> Optional[float]:
    if b == 0:
        return None
    return a / b


def average(numbers) -> float:
    return sum(numbers) / len(numbers)


def clamp(value, lo, hi) -> int:
    return max(lo, min(hi, value))

