from typing import Iterable, Optional


def first_or_none(items: list) -> Optional[str]:
    return items[0] if items else None


def deduplicate(items: Iterable) -> list:
    seen = set()
    out = []
    for x in items:
        if x not in seen:
            seen.add(x)
            out.append(x)
    return out
